import React from 'react';
import { BarChart, Bar, PieChart, Pie, Cell, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';

const AnalyticsDashboard = ({ analytics, loading, onRefresh }) => {
  if (loading) {
    return (
      <div className="loading">
        <div className="spinner"></div>
        <span>Loading analytics...</span>
      </div>
    );
  }

  if (!analytics) {
    return (
      <div className="card">
        <h2 className="card-title">📊 Analytics Dashboard</h2>
        <div className="alert alert-info">
          No analytics data available yet. Start by onboarding workers and processing claims.
        </div>
      </div>
    );
  }

  const { stats, riskDistribution, claimsByType, workers, fraudAlerts } = analytics;

  // Prepare chart data
  const riskData = [
    { name: 'Low Risk', value: riskDistribution.low, color: '#48bb78' },
    { name: 'Medium Risk', value: riskDistribution.medium, color: '#ed8936' },
    { name: 'High Risk', value: riskDistribution.high, color: '#f56565' }
  ];

  const claimsData = [
    { name: 'Weather Claims', value: claimsByType.weather, color: '#4299e1' },
    { name: 'Other Claims', value: claimsByType.other, color: '#9f7aea' }
  ];

  const fraudData = [
    { name: 'Safe', value: workers.filter(w => w.fraudScore <= 30).length, color: '#48bb78' },
    { name: 'Flagged', value: workers.filter(w => w.fraudScore > 30 && w.fraudScore <= 60).length, color: '#ed8936' },
    { name: 'Fraud', value: workers.filter(w => w.fraudScore > 60).length, color: '#f56565' }
  ];

  return (
    <div>
      {/* Stats Cards */}
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-value">{stats.activePolicies}</div>
          <div className="stat-label">Active Weekly Policies</div>
          <div className="stat-change positive">↑ 12% from last week</div>
        </div>
        <div className="stat-card">
          <div className="stat-value">{stats.claimsTriggered}</div>
          <div className="stat-label">Claims Triggered</div>
          <div className="stat-change positive">↑ 8% from last week</div>
        </div>
        <div className="stat-card">
          <div className="stat-value">{stats.fraudFlags}</div>
          <div className="stat-label">Fraud Flags</div>
          <div className="stat-change negative">↑ 3% from last week</div>
        </div>
        <div className="stat-card">
          <div className="stat-value">₹{stats.totalPayoutVolume.toLocaleString()}</div>
          <div className="stat-label">Estimated Payout Volume</div>
          <div className="stat-change positive">↑ 15% from last week</div>
        </div>
      </div>

      {/* Charts Section */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(400px, 1fr))', gap: '2rem', marginBottom: '2rem' }}>
        {/* Risk Distribution Chart */}
        <div className="card">
          <h3 className="card-title">📊 Risk Score Distribution</h3>
          <ResponsiveContainer width="100%" height={300}>
            <PieChart>
              <Pie
                data={riskData}
                cx="50%"
                cy="50%"
                labelLine={false}
                label={({ name, value, percent }) => value > 0 ? `${name}: ${value} (${(percent * 100).toFixed(0)}%)` : ''}
                outerRadius={80}
                fill="#8884d8"
                dataKey="value"
                animationBegin={0}
                animationDuration={800}
                minAngle={5}
              >
                {riskData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip 
                contentStyle={{
                  backgroundColor: 'rgba(255, 255, 255, 0.95)',
                  border: '1px solid #e2e8f0',
                  borderRadius: '8px'
                }}
              />
              <Legend 
                verticalAlign="bottom" 
                height={36}
                formatter={(value, entry) => (
                  <span style={{ color: entry.color, fontWeight: '500' }}>
                    {value}: {entry.payload.value}
                  </span>
                )}
              />
            </PieChart>
          </ResponsiveContainer>

          {/* Risk Summary */}
          <div style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(3, 1fr)', 
            gap: '0.5rem',
            marginTop: '1rem',
            padding: '1rem',
            backgroundColor: '#f7fafc',
            borderRadius: '8px'
          }}>
            {riskData.map((item, index) => (
              <div key={index} style={{ textAlign: 'center' }}>
                <div style={{ 
                  width: '12px', 
                  height: '12px', 
                  backgroundColor: item.color, 
                  borderRadius: '50%',
                  margin: '0 auto 0.25rem auto'
                }}></div>
                <div style={{ fontSize: '0.85rem', color: '#718096' }}>{item.name}</div>
                <div style={{ fontSize: '1.1rem', fontWeight: 'bold', color: '#4a5568' }}>
                  {item.value}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Claims by Type Chart */}
        <div className="card">
          <h3 className="card-title">📈 Claims by Disruption Type</h3>
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={claimsData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" />
              <XAxis 
                dataKey="name" 
                tick={{ fill: '#718096', fontSize: 12 }}
                axisLine={{ stroke: '#e2e8f0' }}
              />
              <YAxis 
                tick={{ fill: '#718096', fontSize: 12 }}
                axisLine={{ stroke: '#e2e8f0' }}
              />
              <Tooltip 
                contentStyle={{
                  backgroundColor: 'rgba(255, 255, 255, 0.95)',
                  border: '1px solid #e2e8f0',
                  borderRadius: '8px'
                }}
                formatter={(value) => [`${value} claims`, 'Count']}
              />
              <Bar 
                dataKey="value" 
                radius={[8, 8, 0, 0]}
                animationBegin={0}
                animationDuration={800}
              >
                {claimsData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>

          {/* Claims Summary */}
          <div style={{ 
            display: 'flex', 
            justifyContent: 'space-around',
            marginTop: '1rem',
            padding: '1rem',
            backgroundColor: '#f7fafc',
            borderRadius: '8px'
          }}>
            {claimsData.map((item, index) => (
              <div key={index} style={{ textAlign: 'center' }}>
                <div style={{ 
                  width: '12px', 
                  height: '12px', 
                  backgroundColor: item.color, 
                  borderRadius: '2px',
                  margin: '0 auto 0.25rem auto'
                }}></div>
                <div style={{ fontSize: '0.85rem', color: '#718096' }}>{item.name}</div>
                <div style={{ fontSize: '1.1rem', fontWeight: 'bold', color: '#4a5568' }}>
                  {item.value}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Fraud Detection Analysis */}
      <div className="card">
        <h3 className="card-title">🔍 Fraud Detection Analysis</h3>

        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '2rem' }}>
          {/* Fraud Distribution Chart */}
          <div>
            <h4 style={{ marginBottom: '1rem', color: '#4a5568', fontSize: '1.1rem' }}>
              Fraud Risk Distribution
            </h4>
            <ResponsiveContainer width="100%" height={250}>
              <PieChart>
                <Pie
                  data={fraudData}
                  cx="50%"
                  cy="50%"
                  innerRadius={40}
                  outerRadius={80}
                  fill="#8884d8"
                  paddingAngle={5}
                  dataKey="value"
                  animationBegin={0}
                  animationDuration={800}
                >
                  {fraudData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip 
                  contentStyle={{
                    backgroundColor: 'rgba(255, 255, 255, 0.95)',
                    border: '1px solid #e2e8f0',
                    borderRadius: '8px'
                  }}
                  formatter={(value, name) => [`${value} workers`, name]}
                />
              </PieChart>
            </ResponsiveContainer>

            {/* Fraud Legend */}
            <div style={{ display: 'flex', justifyContent: 'center', gap: '1rem', marginTop: '1rem' }}>
              {fraudData.map((item, index) => (
                <div key={index} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                  <div style={{ 
                    width: '12px', 
                    height: '12px', 
                    backgroundColor: item.color, 
                    borderRadius: '50%'
                  }}></div>
                  <span style={{ fontSize: '0.85rem', color: '#4a5568' }}>
                    {item.name} ({item.value})
                  </span>
                </div>
              ))}
            </div>
          </div>

          {/* Fraud Metrics */}
          <div>
            <h4 style={{ marginBottom: '1rem', color: '#4a5568', fontSize: '1.1rem' }}>
              Fraud Detection Metrics
            </h4>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
              <div style={{
                padding: '1rem',
                backgroundColor: '#f0fff4',
                border: '1px solid #9ae6b4',
                borderRadius: '8px',
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center'
              }}>
                <div>
                  <div style={{ fontSize: '0.9rem', color: '#22543d', fontWeight: '500' }}>
                    ✅ Safe Workers
                  </div>
                  <div style={{ fontSize: '0.8rem', color: '#68d391' }}>
                    Low fraud risk
                  </div>
                </div>
                <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#22543d' }}>
                  {fraudData[0].value}
                </div>
              </div>

              <div style={{
                padding: '1rem',
                backgroundColor: '#fffdf7',
                border: '1px solid #fbd38d',
                borderRadius: '8px',
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center'
              }}>
                <div>
                  <div style={{ fontSize: '0.9rem', color: '#744210', fontWeight: '500' }}>
                    ⚠️ Flagged Workers
                  </div>
                  <div style={{ fontSize: '0.8rem', color: '#f6ad55' }}>
                    Requires review
                  </div>
                </div>
                <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#744210' }}>
                  {fraudData[1].value}
                </div>
              </div>

              <div style={{
                padding: '1rem',
                backgroundColor: '#fff5f5',
                border: '1px solid #fc8181',
                borderRadius: '8px',
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center'
              }}>
                <div>
                  <div style={{ fontSize: '0.9rem', color: '#742a2a', fontWeight: '500' }}>
                    🚨 Fraud Detected
                  </div>
                  <div style={{ fontSize: '0.8rem', color: '#f56565' }}>
                    High risk activity
                  </div>
                </div>
                <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#742a2a' }}>
                  {fraudData[2].value}
                </div>
              </div>
            </div>

            {/* Fraud Rate */}
            <div style={{
              marginTop: '1rem',
              padding: '1rem',
              background: 'linear-gradient(135deg, #667eea, #764ba2)',
              borderRadius: '8px',
              color: 'white',
              textAlign: 'center'
            }}>
              <div style={{ fontSize: '0.9rem', opacity: 0.9 }}>
                Overall Fraud Rate
              </div>
              <div style={{ fontSize: '1.8rem', fontWeight: 'bold' }}>
                {workers.length > 0 ? ((fraudData[2].value / workers.length) * 100).toFixed(1) : '0.0'}%
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Workers Table */}
      <div className="card">
        <h3 className="card-title">👥 Workers Overview</h3>
        <div className="table-container">
          <table className="table">
            <thead>
              <tr>
                <th>Worker</th>
                <th>City</th>
                <th>Premium/Week</th>
                <th>Claim Status</th>
                <th>Fraud Score</th>
                <th>Risk Level</th>
              </tr>
            </thead>
            <tbody>
              {workers.map((worker) => (
                <tr key={worker.id}>
                  <td>{worker.name}</td>
                  <td>{worker.city}</td>
                  <td>₹{worker.premium}</td>
                  <td>
                    <span className={`badge ${worker.claimStatus === 'has_claims' ? 'badge-success' : 'badge-secondary'}`}>
                      {worker.claimStatus === 'has_claims' ? 'Has Claims' : 'No Claims'}
                    </span>
                  </td>
                  <td>
                    <span className={`risk-badge risk-${
                      worker.fraudScore <= 30 ? 'low' : 
                      worker.fraudScore <= 60 ? 'medium' : 'high'
                    }`}>
                      {worker.fraudScore}
                    </span>
                  </td>
                  <td>
                    <span className={`risk-badge risk-${
                      worker.fraudScore <= 30 ? 'low' : 
                      worker.fraudScore <= 60 ? 'medium' : 'high'
                    }`}>
                      {worker.fraudScore <= 30 ? 'SAFE' : 
                       worker.fraudScore <= 60 ? 'FLAGGED' : 'FRAUD'}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Fraud Alerts */}
      {fraudAlerts && fraudAlerts.length > 0 && (
        <div className="card">
          <h3 className="card-title">🚨 Fraud Alerts</h3>
          {fraudAlerts.map((alert) => (
            <div key={alert.id} className="alert alert-danger">
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                  <strong>{alert.type === 'coordinated_fraud' ? '🚨 Coordinated Fraud Detected' : '⚠️ Suspicious Activity'}</strong>
                  <div style={{ marginTop: '0.5rem' }}>{alert.message}</div>
                  <div style={{ fontSize: '0.85rem', marginTop: '0.5rem', opacity: 0.8 }}>
                    Coordinates: {alert.coordinates?.lat}, {alert.coordinates?.lng} | 
                    Time: {new Date(alert.timestamp).toLocaleString()}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Refresh Button */}
      <div style={{ textAlign: 'center', marginTop: '2rem' }}>
        <button className="btn btn-secondary" onClick={onRefresh}>
          🔄 Refresh Analytics
        </button>
      </div>
    </div>
  );
};

export default AnalyticsDashboard;
